package core.org.apache.calcite.schema.impl;

public class DelegatingSchema implements Schema { protected final Schema schema ; public DelegatingSchema ( Schema schema ) { this . schema = schema ; } @ Override public String toString ( ) { return "DelegatingSchema(delegate=" + schema + ")" ; } public boolean isMutable ( ) { return schema . isMutable ( ) ; } public Schema snapshot ( SchemaVersion version ) { return schema . snapshot ( version ) ; } public Expression getExpression ( SchemaPlus parentSchema , String name ) { return schema . getExpression ( parentSchema , name ) ; } public Table getTable ( String name ) { return schema . getTable ( name ) ; } public Set < String > getTableNames ( ) { return schema . getTableNames ( ) ; } public RelProtoDataType getType ( String name ) { return schema . getType ( name ) ; } public Set < String > getTypeNames ( ) { return schema . getTypeNames ( ) ; } public Collection < Function > getFunctions ( String name ) { return schema . getFunctions ( name ) ; } public Set < String > getFunctionNames ( ) { return schema . getFunctionNames ( ) ; } public Schema getSubSchema ( String name ) { return schema . getSubSchema ( name ) ; } public Set < String > getSubSchemaNames ( ) { return schema . getSubSchemaNames ( ) ; } }